import { Type } from '@sinclair/typebox';
import { silSchema } from '../../../schemas/sil.js';
import { parse } from '../../../utils/json.js';
export const parseRawServerServerItemsOptionValue = (value) => {
    if (typeof value !== 'string')
        return;
    return parse(value, Type.Array(silSchema));
};
export const normalizeServerServerItemsOptionValue = (value, option) => value !== undefined && (option.limit === 0 || value.length <= option.limit) ? value : option.def;
export const serializeServerServerItemsOptionValue = (value) => JSON.stringify(value);
export const toServerServerItemsOption = (localize, query, option) => ({
    query,
    name: localize(option.name),
    description: option.description && localize(option.description),
    required: option.required,
    type: option.type,
    itemType: option.itemType,
    def: option.def,
    allowOtherServers: option.allowOtherServers,
    limit: option.limit,
});
